const orderService = uniCloud.importObject('order-service')

const ACCEPTED_VERSION_KEY = 'privacy_consent_accepted_version'
const NOTICE_CACHE_KEY = 'privacy_consent_notice_cache'
const CHECK_INTERVAL_MS = 30 * 1000

let checking = false
let lastCheckAt = 0

function safeNumber(v) {
  const n = Number(v)
  return Number.isFinite(n) ? n : 0
}

function getCurrentRoute() {
  const pages = getCurrentPages()
  if (!pages || !pages.length) return ''
  const current = pages[pages.length - 1]
  return current && current.route ? String(current.route) : ''
}

export function getAcceptedVersion() {
  return safeNumber(uni.getStorageSync(ACCEPTED_VERSION_KEY))
}

export function setAcceptedVersion(version) {
  uni.setStorageSync(ACCEPTED_VERSION_KEY, safeNumber(version))
}

export function getCachedNotice() {
  const raw = uni.getStorageSync(NOTICE_CACHE_KEY)
  if (!raw) return null
  if (typeof raw === 'object') return raw
  try {
    return JSON.parse(raw)
  } catch (e) {
    return null
  }
}

export function setCachedNotice(notice) {
  try {
    uni.setStorageSync(NOTICE_CACHE_KEY, JSON.stringify(notice || {}))
  } catch (e) {
    uni.setStorageSync(NOTICE_CACHE_KEY, notice || {})
  }
}

export async function fetchPrivacyConsentNotice() {
  const res = await orderService.getPrivacyConsentNotice()
  if (!res || res.code !== 0 || !res.data) {
    throw new Error(res?.message || '获取隐私提醒失败')
  }
  const notice = {
    enabled: res.data.enabled === true,
    version: safeNumber(res.data.version),
    title: String(res.data.title || '隐私政策更新提醒'),
    content: String(res.data.content || ''),
    policy_url: String(res.data.policy_url || ''),
    updated_at: safeNumber(res.data.updated_at)
  }
  setCachedNotice(notice)
  return notice
}

export async function checkAndPromptPrivacyConsent({ force = false } = {}) {
  if (checking) return
  const now = Date.now()
  if (!force && now - lastCheckAt < CHECK_INTERVAL_MS) return
  lastCheckAt = now
  checking = true
  try {
    const notice = await fetchPrivacyConsentNotice()
    if (!notice.enabled || !notice.version) return

    const accepted = getAcceptedVersion()
    if (accepted >= notice.version) return

    const route = getCurrentRoute()
    if (route === 'pages/common/privacy/reconsent') return

    uni.navigateTo({
      url: `/pages/common/privacy/reconsent?v=${notice.version}`
    })
  } catch (e) {
    console.warn('[privacy-consent] check failed', e)
  } finally {
    checking = false
  }
}

export async function acceptPrivacyConsent(version) {
  const v = safeNumber(version)
  if (!v) throw new Error('无效版本号')

  setAcceptedVersion(v)

  const token = uni.getStorageSync('uni_id_token')
  if (!token) return { code: 0 }

  const res = await orderService.acceptPrivacyConsent({ version: v })
  if (res && res.code === 'NO_LOGIN') {
    return { code: 0 }
  }
  if (!res || res.code !== 0) {
    throw new Error(res?.message || '记录同意失败')
  }
  return res
}
